}", "new_string": "/**
 * Thrown by date-time arithmetic operations if the result cannot be computed or represented.
 *
 * This exception is thrown in the following situations:
 * - The result of an arithmetic operation exceeds the platform-specific boundaries for the type.
 *   For example, adding a very large period to an [Instant] may exceed [Instant.MAX].
 * - Intermediate computations overflow. For example, when calculating the period between two dates,
 *   if the number of months exceeds [Int.MAX_VALUE] (on JVM only).
 * - An operation involves a date-time value that cannot fit in [LocalDateTime]. For example, trying to
 *   convert [Instant.DISTANT_FUTURE] to [LocalDateTime] may fail on some platforms.
 *
 * Example scenarios:
 * ```
 * // May throw if result is too large
 * val farFuture = Instant.MAX.plus(Duration.INFINITE)
 * 
 * // May throw if intermediate computation overflows
 * val hugeInstant = Instant.fromEpochSeconds(Long.MAX_VALUE)
 * val period = Instant.DISTANT_PAST.periodUntil(hugeInstant, TimeZone.UTC)
 * ```
 *
 * @see Instant for instant arithmetic operations.
 * @see LocalDate for date arithmetic operations.
 */
public class DateTimeArithmeticException: RuntimeException {
    public constructor(): super()
    public constructor(message: String): super(message)
    public constructor(cause: Throwable): super(cause)
    public constructor(message: String, cause: Throwable): super(message, cause)
}

/**
 * Thrown when attempting to construct a [TimeZone] with an invalid ID.
 *
 * This exception is thrown by [TimeZone.of] when:
 * - The provided time zone ID has an invalid format.
 * - The time zone ID is not found in the system's time zone database.
 * - The time zone ID represents a fixed offset that is outside the valid range (typically ±18:00).
 *
 * Example scenarios:
 * ```
 * // Invalid format
 * TimeZone.of("Not/A/Real/TimeZone") // throws IllegalTimeZoneException
 * 
 * // Invalid fixed offset
 * TimeZone.of("+99:00") // throws IllegalTimeZoneException
 * ```
 *
 * To check if a time zone ID is valid before using it, you can catch this exception or check against
 * [TimeZone.availableZoneIds].
 *
 * @see TimeZone.of for constructing time zones by ID.
 * @see TimeZone.availableZoneIds for the set of valid time zone IDs.
 */
public class IllegalTimeZoneException: IllegalArgumentException {
    public constructor(): super()
    public constructor(message: String): super(message)
    public constructor(cause: Throwable): super(cause)
    public constructor(message: String, cause: Throwable): super(message, cause)
}"}

